const DROP_ACARS_LABELS = ["_d"];
const LIBACARS_LABELS = ["A6", "AA", "B6", "BA", "H1", "SA", "MA"];

function looksLikeAirframesEvent(value) {
    return value && typeof value === "object" && (
        value.id || value.timestamp || value.station || value.airframe || value.source
    );
}

function extractEvent(value) {
    if (!value || typeof value !== "object") return {};
    if (looksLikeAirframesEvent(value)) return value;
    for (const key of ["payload", "event", "message", "data"]) {
        if (looksLikeAirframesEvent(value[key])) return value[key];
    }
    return value;
}

function response(payload) {
    return {
        req: msg.req,
        res: msg.res,
        statusCode: 200,
        headers: { "content-type": "application/json" },
        payload
    };
}

function inferDirection(event) {
    const direction = String(event.link_direction || "").toLowerCase();
    if (["u", "uplink", "ground-to-air", "ground_to_air"].includes(direction)) return "u";
    if (["d", "downlink", "air-to-ground", "air_to_ground"].includes(direction)) return "d";
    return "d";
}

function shellQuote(value) {
    return `'${String(value).replace(/'/g, `'\''`)}'`;
}

function buildLibacarsMsg(event, normalized) {
    const label = String(event.label || "").trim().toUpperCase();
    const text  = String(event.text  || "");
    if (!label || !text || !LIBACARS_LABELS.includes(label)) return null;
    const direction = inferDirection(event);
    return {
        payload: `${direction} ${shellQuote(label)} ${shellQuote(text)}`,
        normalized,
        libacars_meta: { label, direction }
    };
}

const envelope = msg.payload || {};
const event    = extractEvent(envelope);
const label    = String(event.label || "").trim().toLowerCase();

if (DROP_ACARS_LABELS.includes(label)) {
    return [
        null, null,
        response({ ok: true, dropped: true, reason: "acars_label", label: event.label, id: event.id }),
        null, null
    ];
}

const flight  = event.flight   || {};
const airframe = event.airframe || {};
const station  = event.station  || {};
const now      = new Date().toISOString();

const normalized = {
    received_at:   now,
    id:            event.id,
    timestamp:     event.timestamp || event.created_at || now,
    station:       station.ident,
    country:       station.country_code,
    flight:        flight.flight_iata || flight.flight_icao || flight.flight,
    airframe_icao: airframe.icao,
    tail:          airframe.tail || event.tail,
    military:      airframe.military,
    source:        event.source,
    source_type:   event.source_type,
    frequency:     event.frequency,
    label:         event.label,
    mode:          event.mode,
    text:          event.text,
    raw:           event
};

let recent = flow.get("airframes_recent") || [];
recent.unshift(normalized);
recent = recent.slice(0, 500);
flow.set("airframes_recent", recent);

const debugMsg    = { payload: normalized };
const fileMsg     = { payload: JSON.stringify(normalized) };
const responseMsg = response({ ok: true, id: normalized.id, received_at: normalized.received_at });
const libacarsMsg = buildLibacarsMsg(event, normalized);

// Output 5: pass ALL messages (with label+text) to acars-decoder-typescript
const acarsDecoderMsg = (normalized.label && normalized.text)
    ? { payload: normalized, normalized }
    : null;

return [debugMsg, fileMsg, responseMsg, libacarsMsg, acarsDecoderMsg];

// ── acars-decoder-typescript integration ──────────────────────────────────
// Requires: cd ~/.node-red && npm install @airframes/acars-decoder
// Node-RED settings.js must have:  functionExternalModules: true
//
// This node decodes the ACARS text payload for ALL labels using the
// @airframes/acars-decoder npm package, then enriches the event and
// updates the flow-level cache so the dashboard shows decoded data.
// It runs IN PARALLEL with the libacars exec branch (which handles
// ARINC-622 / CPDLC labels via the C binary decode_acars_apps).
// ──────────────────────────────────────────────────────────────────────────

const normalized = msg.normalized || msg.payload || {};
const event      = normalized.raw || {};

const label  = String(normalized.label  || event.label  || "").trim().toUpperCase();
const text   = String(normalized.text   || event.text   || "").trim();
const tail   = String(normalized.tail   || event.tail   || "").trim();
const flight = String(normalized.flight || "").trim();

if (!label || !text) {
    return [null, null];
}

let decoded = null;
let decodeError = null;

try {
    // The module is registered in the "Setup" tab of this function node
    // as:  Name = AcarsDecoder  |  Module = @airframes/acars-decoder
    const { MessageDecoder } = AcarsDecoder;
    const decoder = new MessageDecoder();

    // Build the message object the decoder expects
    const msgObj = { label, text };
    if (tail)   msgObj.tail   = tail;
    if (flight) msgObj.flight = flight;

    decoded = decoder.decode(msgObj);
} catch (err) {
    decodeError = err.message || String(err);
    node.warn("acars-decoder error [" + label + "]: " + decodeError);
}

// Only enrich if the decoder produced meaningful output
if (!decoded) {
    return [null, null];
}

const enriched = {
    ...normalized,
    acars_decoded: {
        ok:        true,
        label,
        decoded,
        decoder:   "acars-decoder-typescript"
    }
};

// Update the flow cache: replace existing entry by key
let recent = flow.get("airframes_recent") || [];
const key  = enriched.id || `${enriched.timestamp}-${enriched.station}-${enriched.text}`;
recent = recent.filter(e => {
    const k = e.id || `${e.timestamp}-${e.station}-${e.text}`;
    return k !== key;
});
recent.unshift(enriched);
recent = recent.slice(0, 500);
flow.set("airframes_recent", recent);

return [
    { payload: enriched },
    { payload: JSON.stringify(enriched) }
];

const normalized = msg.normalized || {};
const meta       = msg.libacars_meta || {};
const stdout     = String(msg.payload || "").trim();

if (!stdout) return [null, null];

function parseLibacarsOutput(output) {
    try { return JSON.parse(output); } catch (err) {}
    const lines = output.split(/\r?\n/).map(l => l.trim()).filter(Boolean);
    for (let i = lines.length - 1; i >= 0; i--) {
        const line = lines[i];
        if (!line.startsWith("{") && !line.startsWith("[")) continue;
        try { return JSON.parse(line); } catch (err) {}
    }
    return output;
}

const decoded = parseLibacarsOutput(stdout);
const enriched = {
    ...normalized,
    libacars: {
        ok:        true,
        label:     meta.label,
        direction: meta.direction,
        decoded,
        decoder:   "libacars"
    }
};

let recent = flow.get("airframes_recent") || [];
const key  = enriched.id || `${enriched.timestamp}-${enriched.station}-${enriched.text}`;
recent = recent.filter(e => {
    const k = e.id || `${e.timestamp}-${e.station}-${e.text}`;
    return k !== key;
});
recent.unshift(enriched);
recent = recent.slice(0, 500);
flow.set("airframes_recent", recent);

return [
    { payload: enriched },
    { payload: JSON.stringify(enriched) }
];

const stderr = String(msg.payload || "").trim();
if (!stderr) return null;
msg.payload = {
    libacars_error: stderr,
    id:        msg.normalized?.id,
    label:     msg.libacars_meta?.label,
    direction: msg.libacars_meta?.direction
};
return msg;

function normalize(record) {
    if (!record || typeof record !== "object") return null;
    if (record.raw || record.received_at || record.airframe_icao) return record;
    const flight   = record.flight   || {};
    const airframe = record.airframe || {};
    const station  = record.station  || {};
    return {
        received_at:   record.received_at,
        id:            record.id,
        timestamp:     record.timestamp || record.created_at,
        station:       station.ident,
        country:       station.country_code,
        flight:        flight.flight_iata || flight.flight_icao || flight.flight,
        airframe_icao: airframe.icao,
        tail:          airframe.tail || record.tail,
        military:      airframe.military,
        source:        record.source,
        source_type:   record.source_type,
        frequency:     record.frequency,
        label:         record.label,
        mode:          record.mode,
        text:          record.text,
        raw:           record
    };
}

const limit  = Math.max(1, Math.min(parseInt(msg.req?.query?.limit || "250", 10) || 250, 2000));
const lines  = String(msg.payload || "").split(/\r?\n/).filter(Boolean);
const stored = [];

for (let i = lines.length - 1; i >= 0 && stored.length < limit; i--) {
    try {
        const parsed = normalize(JSON.parse(lines[i]));
        if (parsed) stored.push(parsed);
    } catch (err) { /* ignore non-JSON lines */ }
}

const recent = flow.get("airframes_recent") || [];
const byId   = new Map();
for (const event of [...recent, ...stored]) {
    const key = event.id || `${event.timestamp}-${event.station}-${event.text}`;
    if (!byId.has(key)) byId.set(key, event);
}

msg.headers = { "content-type": "application/json; charset=utf-8", "cache-control": "no-store" };
msg.payload = JSON.stringify([...byId.values()].slice(0, limit));
return msg;

const icao = String(msg.req?.params?.icao || "").trim().toUpperCase();
if (!/^[A-F0-9]{6}$/.test(icao)) {
    msg.statusCode = 400;
    msg.headers    = { "content-type": "application/json; charset=utf-8" };
    msg.payload    = { error: "invalid_icao", icao };
    return [null, msg];
}
msg.url     = `https://api.airframes.io/airframes/icao/${encodeURIComponent(icao)}`;
msg.method  = "GET";
msg.headers = { accept: "application/json" };
return [msg, null];

msg.headers = { "content-type": "application/json; charset=utf-8", "cache-control": "no-store" };
if (msg.statusCode && msg.statusCode >= 400) {
    msg.payload = { error: "airframes_api_error", statusCode: msg.statusCode, response: msg.payload };
    return msg;
}
return msg;

const content = String(msg.payload || "");
const lines   = content.split(/\r?\n/).filter(l => l.trim().length > 0);
let validJson = 0, invalidJson = 0;
let acarsDecodedCount = 0, libacarsDecodedCount = 0;
const byLabel = {}, bySource = {};
let latestTimestamp = null, earliestTimestamp = null;

for (const line of lines) {
    try {
        const event     = JSON.parse(line);
        const label     = event.label     || event.raw?.label     || "unknown";
        const source    = event.source    || event.raw?.source    || "unknown";
        const timestamp = event.timestamp || event.raw?.timestamp;
        validJson += 1;
        if (event.acars_decoded?.ok) acarsDecodedCount += 1;
        if (event.libacars?.ok)      libacarsDecodedCount += 1;
        byLabel[label]   = (byLabel[label]   || 0) + 1;
        bySource[source] = (bySource[source] || 0) + 1;
        if (timestamp) {
            if (!latestTimestamp   || timestamp > latestTimestamp)   latestTimestamp   = timestamp;
            if (!earliestTimestamp || timestamp < earliestTimestamp) earliestTimestamp = timestamp;
        }
    } catch (err) {
        invalidJson += 1;
    }
}

msg.headers = { "content-type": "application/json; charset=utf-8", "cache-control": "no-store" };
msg.payload = JSON.stringify({
    file:                   "/mnt/ssl/acars",
    messages:               lines.length,
    valid_json:             validJson,
    invalid_json:           invalidJson,
    acars_decoded_count:    acarsDecodedCount,
    libacars_decoded_count: libacarsDecodedCount,
    earliest_timestamp:     earliestTimestamp,
    latest_timestamp:       latestTimestamp,
    by_label:               byLabel,
    by_source:              bySource
});
return msg;
